import sys

def suma_recursiva(lista):
    if not lista:
        return 0
    return lista[0] + suma_recursiva(lista[1:])

def suma_iterativa(lista):
    total = 0
    for x in lista:
        total += x
    return total

datos = list(range(900))
print(sys.getrecursionlimit())
print(suma_recursiva(datos))
print(suma_iterativa(list(range(3000))))

def validar(d, nominal, tol):
    return abs(d - nominal) <= tol

def tasa(medidas, nominal, tol):
    aprobadas = [d for d in medidas if validar(d, nominal, tol)]
    return len(aprobadas) / len(medidas) * 100

def version_monolitica(medidas, nominal, tol):
    c = 0
    for d in medidas:
        if abs(d - nominal) <= tol:
            c += 1
    return c / len(medidas) * 100

m = [10.0, 10.2, 9.5, 10.1]
assert tasa(m, 10.0, 0.3) == version_monolitica(m, 10.0, 0.3)
print(f"Aprobacion: {tasa(m, 10.0, 0.3):.1f}%")
